mapper.select:
/* Baim01Mapper.selectSiteInfoList */ SELECT '' AS chk , A.SITE_CD AS siteCd , A.SITE_NO AS siteNo , A.SITE_NM AS siteNm , A.CMPNY_CD AS cmpnyCd , A.ADDR_1 AS addr1 , A.ADDR_2 AS addr2 , A.ZIP_CODE AS zipCode , A.STR_DATE AS strDate , A.END_DATE AS endDate , A.USE_YN AS useYn , A.SITE_ADMIN_ID AS siteAdminId , B.USER_ID AS siteAdminNm , A.TEL_NO AS telNo , IFNULL(A.GPS_RANGE, 0) AS gpsRange , A.SITE_DESC AS siteDesc FROM TB_SITE A LEFT JOIN TB_USER B ON ( A.CMPNY_CD = B.CMPNY_CD AND A.SITE_ADMIN_ID = B.USER_ID ) WHERE 1=1 AND A.CMPNY_CD = #{token.gv_cmpnyCd}
AND A.SITE_CD = #{param.siteCd}
AND A.SITE_NO = #{param.siteNo}
AND A.SITE_NM LIKE CONCAT('%', #{param.siteNm}, '%')
AND A.USE_YN = #{param.useYn}
